import type { Express } from "express";
import { createServer, type Server } from "http";
import { WebSocketServer, WebSocket } from "ws";
import { randomUUID } from "crypto";
import { storage } from "./storage";
import { exchangeService, createTickerStream, createKlinesStream } from "./exchangeService";
import { analyzeAndRespond } from "./openai";
import { tradingBot } from "./tradingBot";
import { strategyOrchestrator } from "./strategyOrchestrator";
import { notificationService } from "./notificationService";
import { getCoinstoreBalance } from "./coinstoreApi";
import { getBydfiBalance } from "./bydfiApi";
import { getBitunixBalance } from "./bitunixApi";
import { getToobitBalance } from "./toobitApi";
import { apiCredentialsSchema, manualOrderSchema, riskParametersSchema, insertTradeSchema } from "@shared/schema";
import type { Exchange, TradeCycleState, StopOrder, RunningStrategyStatus } from "@shared/schema";
import { z } from "zod";

// Schema for trade update validation
const updateTradeSchema = z.object({
  exitPrice: z.number().optional(),
  pnl: z.number().optional(),
  pnlPercent: z.number().optional(),
  status: z.enum(["open", "closed", "liquidated"]).optional(),
  closedAt: z.string().datetime().transform(s => new Date(s)).optional(),
  closeReason: z.string().optional(),
});

export async function registerRoutes(app: Express): Promise<Server> {
  const httpServer = createServer(app);

  // WebSocket server for real-time data
  const wss = new WebSocketServer({ server: httpServer, path: "/ws" });
  const clients = new Set<WebSocket>();
  // Track ticker streams per client (not globally) to prevent orphaned streams
  const clientStreams = new Map<WebSocket, Map<string, { stop: () => void }>>();

  wss.on("connection", (ws) => {
    clients.add(ws);
    clientStreams.set(ws, new Map());
    notificationService.registerClient(ws);
    console.log("WebSocket client connected");

    ws.on("message", async (message) => {
      try {
        const data = JSON.parse(message.toString());

        if (data.type === "subscribe" && data.symbol) {
          const tickerStreamKey = `ticker:${data.exchange}:${data.symbol}`;
          const klinesStreamKey = `klines:${data.exchange}:${data.symbol}:${data.timeframe || "15m"}`;
          const wsStreams = clientStreams.get(ws);

          if (wsStreams) {
            // Stop ALL existing streams for this client - only one market should be active at a time
            wsStreams.forEach((stream, existingKey) => {
              stream.stop();
              console.log(`Stopped stream for ${existingKey} (switching market)`);
            });
            wsStreams.clear();

            // Start new ticker stream for this client
            const tickerStream = createTickerStream(
              data.exchange as Exchange,
              data.symbol,
              (streamData) => {
                if (ws.readyState === WebSocket.OPEN) {
                  ws.send(JSON.stringify({ 
                    type: "ticker", 
                    data: streamData.ticker,
                    dataSource: streamData.dataSource,
                    ...(streamData.dataError ? { dataError: streamData.dataError } : {})
                  }));
                }
              }
            );
            wsStreams.set(tickerStreamKey, tickerStream);
            console.log(`Started ticker stream for ${tickerStreamKey}`);

            // Start new klines stream for this client - updates chart data periodically
            const klinesStream = createKlinesStream(
              data.exchange as Exchange,
              data.symbol,
              data.timeframe || "15m",
              (streamData) => {
                if (ws.readyState === WebSocket.OPEN) {
                  ws.send(JSON.stringify({ 
                    type: "klines", 
                    data: streamData.klines,
                    dataSource: streamData.dataSource,
                    ...(streamData.dataError ? { dataError: streamData.dataError } : {})
                  }));
                }
              },
              3000 // Update klines every 3 seconds for higher resolution
            );
            wsStreams.set(klinesStreamKey, klinesStream);
            console.log(`Started klines stream for ${klinesStreamKey}`);
          }
        }
      } catch (error) {
        console.error("WebSocket message error:", error);
      }
    });

    ws.on("close", () => {
      // Stop all ticker streams for this client when they disconnect
      const wsStreams = clientStreams.get(ws);
      if (wsStreams) {
        wsStreams.forEach((stream, streamKey) => {
          stream.stop();
          console.log(`Stopped orphaned ticker stream for ${streamKey} on client disconnect`);
        });
        clientStreams.delete(ws);
      }
      clients.delete(ws);
      notificationService.unregisterClient(ws);
      console.log("WebSocket client disconnected");
    });
  });

  // Broadcast function for real-time updates
  function broadcast(type: string, data: any) {
    const message = JSON.stringify({ type, data });
    clients.forEach((client) => {
      if (client.readyState === WebSocket.OPEN) {
        client.send(message);
      }
    });
  }

  // ============ AUTH ROUTES ============

  app.post("/api/auth/connect", async (req, res) => {
    try {
      const credentials = apiCredentialsSchema.parse(req.body);

      // Validate credentials with exchange
      const isValid = await exchangeService.validateCredentials(credentials);

      if (!isValid) {
        return res.status(401).json({ 
          success: false, 
          error: "Invalid API credentials. Please check your keys." 
        });
      }

      // Save credentials
      await storage.saveCredentials(credentials);

      res.json({ success: true, message: "Connected successfully" });
    } catch (error) {
      if (error instanceof z.ZodError) {
        return res.status(400).json({ success: false, error: error.errors[0].message });
      }
      res.status(500).json({ success: false, error: (error as Error).message });
    }
  });

  app.post("/api/auth/disconnect", async (req, res) => {
    try {
      const { exchange } = req.body;
      if (exchange) {
        await storage.clearCredentials(exchange as Exchange);
      }
      res.json({ success: true });
    } catch (error) {
      res.status(500).json({ success: false, error: (error as Error).message });
    }
  });

  // Get account balance
  app.get("/api/balance", async (req, res) => {
    try {
      const exchange = req.query.exchange as Exchange;
      if (!exchange) {
        return res.status(400).json({ success: false, error: "Exchange required" });
      }

      const credentials = await storage.getCredentials(exchange);
      if (!credentials) {
        return res.status(401).json({ success: false, error: "Not authenticated" });
      }

      let result;
      if (exchange === "coinstore") {
        result = await getCoinstoreBalance(credentials);
      } else if (exchange === "bydfi") {
        result = await getBydfiBalance(credentials);
      } else if (exchange === "bitunix") {
        result = await getBitunixBalance(credentials);
      } else if (exchange === "toobit") {
        result = await getToobitBalance(credentials);
      } else {
        return res.status(400).json({ success: false, error: "Unsupported exchange" });
      }

      if (!result.success) {
        return res.status(500).json({ 
          success: false, 
          error: result.error || "Failed to fetch balance" 
        });
      }

      res.json({ success: true, balances: result.data });
    } catch (error) {
      res.status(500).json({ success: false, error: (error as Error).message });
    }
  });

  // ============ MARKET DATA ROUTES ============

  app.get("/api/exchange-info", async (req, res) => {
    try {
      const exchange = req.query.exchange as Exchange;
      if (!exchange) {
        return res.status(400).json({ success: false, error: "Exchange required" });
      }

      const info = exchangeService.getExchangeInfo(exchange);
      res.json({ success: true, info });
    } catch (error) {
      res.status(500).json({ success: false, error: (error as Error).message });
    }
  });

  app.get("/api/markets", async (req, res) => {
    try {
      const exchange = req.query.exchange as Exchange;
      if (!exchange) {
        return res.status(400).json({ success: false, error: "Exchange required" });
      }

      // getMarkets now returns MarketsResult with data source embedded
      const result = await exchangeService.getMarkets(exchange);
      await storage.setMarkets(exchange, result.markets);

      res.json({ 
        success: true, 
        exchange, 
        markets: result.markets, 
        dataSource: result.dataSource,
        ...(result.dataError ? { dataError: result.dataError } : {})
      });
    } catch (error) {
      res.status(500).json({ success: false, error: (error as Error).message });
    }
  });

  app.get("/api/ticker", async (req, res) => {
    try {
      const exchange = req.query.exchange as Exchange;
      const symbol = req.query.symbol as string;

      if (!exchange || !symbol) {
        return res.status(400).json({ success: false, error: "Exchange and symbol required" });
      }

      // getTicker now returns TickerResult with data source embedded
      const result = await exchangeService.getTicker(exchange, symbol);
      await storage.setTicker(exchange, symbol, result.ticker);

      res.json({ 
        success: true, 
        ticker: result.ticker, 
        dataSource: result.dataSource,
        ...(result.dataError ? { dataError: result.dataError } : {})
      });
    } catch (error) {
      res.status(500).json({ success: false, error: (error as Error).message });
    }
  });

  app.get("/api/klines", async (req, res) => {
    try {
      const exchange = req.query.exchange as Exchange;
      const symbol = req.query.symbol as string;
      const timeframe = (req.query.timeframe as string) || "15m";
      const limit = parseInt(req.query.limit as string) || 100;

      if (!exchange || !symbol) {
        return res.status(400).json({ success: false, error: "Exchange and symbol required" });
      }

      // getKlines now returns KlinesResult with data source embedded
      const result = await exchangeService.getKlines(exchange, symbol, timeframe, limit);
      await storage.setKlines(exchange, symbol, timeframe, result.klines);

      res.json({ 
        success: true, 
        klines: result.klines, 
        dataSource: result.dataSource,
        ...(result.dataError ? { dataError: result.dataError } : {})
      });
    } catch (error) {
      res.status(500).json({ success: false, error: (error as Error).message });
    }
