import { useState, useEffect, useRef } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import { Switch } from "@/components/ui/switch";
import { 
  Bell, 
  Settings, 
  X, 
  TrendingUp, 
  TrendingDown, 
  AlertTriangle,
  Target,
  Activity,
  Info,
  Check
} from "lucide-react";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";
import type { Notification, NotificationSettings } from "@shared/schema";

function formatTimeAgo(timestamp: Date | string): string {
  const date = new Date(timestamp);
  const now = new Date();
  const diff = now.getTime() - date.getTime();
  const minutes = Math.floor(diff / 60000);
  const hours = Math.floor(diff / 3600000);
  const days = Math.floor(diff / 86400000);

  if (minutes < 1) return "Just now";
  if (minutes < 60) return `${minutes}m ago`;
  if (hours < 24) return `${hours}h ago`;
  return `${days}d ago`;
}

function getNotificationIcon(type: string) {
  switch (type) {
    case "trade_open":
      return <Activity className="w-4 h-4 text-blue-500" />;
    case "trade_close":
      return <TrendingUp className="w-4 h-4 text-green-500" />;
    case "stop_loss":
      return <TrendingDown className="w-4 h-4 text-red-500" />;
    case "take_profit":
      return <Target className="w-4 h-4 text-green-500" />;
    case "trailing_stop":
      return <Activity className="w-4 h-4 text-yellow-500" />;
    case "error":
      return <AlertTriangle className="w-4 h-4 text-destructive" />;
    case "info":
    default:
      return <Info className="w-4 h-4 text-muted-foreground" />;
  }
}

function NotificationItem({ notification, onMarkRead }: { 
  notification: Notification; 
  onMarkRead: (id: number) => void;
}) {
  const pnl = notification.pnl;
  const isProfitable = pnl !== null && pnl >= 0;

  return (
    <div
      className={`p-3 hover-elevate cursor-pointer transition-colors ${
        !notification.isRead ? "bg-accent/30" : ""
      }`}
      onClick={() => !notification.isRead && onMarkRead(notification.id)}
      data-testid={`notification-item-${notification.id}`}
    >
      <div className="flex items-start gap-3">
        <div className="mt-0.5">
          {getNotificationIcon(notification.type)}
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center justify-between gap-2">
            <p className="text-sm font-medium truncate">{notification.title}</p>
            {!notification.isRead && (
              <div className="w-2 h-2 rounded-full bg-primary flex-shrink-0" />
            )}
          </div>
          <p className="text-sm text-muted-foreground line-clamp-2">
            {notification.message}
          </p>
          <div className="flex items-center gap-2 mt-1">
            <span className="text-xs text-muted-foreground">
              {formatTimeAgo(notification.createdAt)}
            </span>
            {pnl !== null && (
              <Badge 
                variant={isProfitable ? "default" : "destructive"} 
                className="text-xs px-1.5 py-0"
              >
                {isProfitable ? "+" : ""}{pnl.toFixed(2)}
              </Badge>
            )}
            {notification.exchange && (
              <Badge variant="outline" className="text-xs px-1.5 py-0">
                {notification.exchange}
              </Badge>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

function NotificationSettingsPanel({ settings, onUpdate }: {
  settings: NotificationSettings | null;
  onUpdate: (settings: Partial<NotificationSettings>) => void;
}) {
  const [localSettings, setLocalSettings] = useState<Partial<NotificationSettings>>({
    tradeOpenEnabled: true,
    tradeCloseEnabled: true,
    stopLossEnabled: true,
    takeProfitEnabled: true,
    browserEnabled: false,
    soundEnabled: false,
    minPnlAlert: 0,
    ...settings,
  });

  const handleToggle = (key: keyof NotificationSettings, value: boolean) => {
    const newSettings = { ...localSettings, [key]: value };
    setLocalSettings(newSettings);
    onUpdate(newSettings);
  };

  return (
    <div className="p-4 space-y-4">
      <h4 className="text-sm font-medium">Notification Settings</h4>

      <div className="space-y-3">
        <div className="flex items-center justify-between">
          <span className="text-sm">Trade Opens</span>
          <Switch
            checked={localSettings.tradeOpenEnabled}
            onCheckedChange={(v) => handleToggle("tradeOpenEnabled", v)}
            data-testid="switch-trade-open"
          />
        </div>

        <div className="flex items-center justify-between">
          <span className="text-sm">Trade Closes</span>
          <Switch
            checked={localSettings.tradeCloseEnabled}
            onCheckedChange={(v) => handleToggle("tradeCloseEnabled", v)}
            data-testid="switch-trade-close"
          />
        </div>

        <div className="flex items-center justify-between">
          <div>
            <span className="text-sm">Stop-Loss / Trailing Stops</span>
            <p className="text-xs text-muted-foreground">Includes trailing stop triggers</p>
          </div>
          <Switch
            checked={localSettings.stopLossEnabled}
            onCheckedChange={(v) => handleToggle("stopLossEnabled", v)}
            data-testid="switch-stop-loss"
          />
        </div>

        <div className="flex items-center justify-between">
          <span className="text-sm">Take-Profit Triggers</span>
          <Switch
            checked={localSettings.takeProfitEnabled}
            onCheckedChange={(v) => handleToggle("takeProfitEnabled", v)}
            data-testid="switch-take-profit"
          />
        </div>

        <Separator className="my-2" />

        <div className="flex items-center justify-between">
          <span className="text-sm">Browser Notifications</span>
          <Switch
            checked={localSettings.browserEnabled}
            onCheckedChange={(v) => handleToggle("browserEnabled", v)}
            data-testid="switch-browser"
          />
        </div>

        <div className="flex items-center justify-between">
          <span className="text-sm">Sound Alerts</span>
          <Switch
            checked={localSettings.soundEnabled}
            onCheckedChange={(v) => handleToggle("soundEnabled", v)}
            data-testid="switch-sound"
          />
        </div>
      </div>
    </div>
  );
}

export function NotificationPanel() {
  const [open, setOpen] = useState(false);
  const [tab, setTab] = useState<"notifications" | "settings">("notifications");

  const { data: notificationsData, isLoading } = useQuery<{ notifications: Notification[] }>({
    queryKey: ["/api/notifications"],
    refetchInterval: 30000,
  });

  const { data: settingsData } = useQuery<{ settings: NotificationSettings }>({
    queryKey: ["/api/notifications/settings"],
  });

  const notifications = notificationsData?.notifications || [];
  const settings = settingsData?.settings || null;
  const unreadCount = notifications.filter((n) => !n.isRead).length;

  const markReadMutation = useMutation({
    mutationFn: async (id: number) => {
      await apiRequest("PATCH", `/api/notifications/${id}/read`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/notifications"] });
    },
  });

  const markAllReadMutation = useMutation({
    mutationFn: async () => {
      await apiRequest("POST", "/api/notifications/mark-all-read");
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/notifications"] });
    },
  });

  const updateSettingsMutation = useMutation({
    mutationFn: async (newSettings: Partial<NotificationSettings>) => {
      await apiRequest("PUT", "/api/notifications/settings", newSettings);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/notifications/settings"] });
    },
  });

  const handleMarkRead = (id: number) => {
    markReadMutation.mutate(id);
  };

  const handleMarkAllRead = () => {
    markAllReadMutation.mutate();
  };

  const handleUpdateSettings = (newSettings: Partial<NotificationSettings>) => {
    updateSettingsMutation.mutate(newSettings);
  };

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          className="relative"
          data-testid="button-notifications"
        >
          <Bell className="h-5 w-5" />
          {unreadCount > 0 && (
            <span className="absolute -top-0.5 -right-0.5 min-w-[18px] h-[18px] rounded-full bg-destructive text-destructive-foreground text-[10px] font-medium flex items-center justify-center px-1">
              {unreadCount > 99 ? "99+" : unreadCount}
            </span>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent 
        className="w-80 p-0" 
        align="end"
        data-testid="notification-popover"
      >
        <Tabs value={tab} onValueChange={(v) => setTab(v as typeof tab)}>
          <div className="flex items-center justify-between border-b px-3 py-2">
            <TabsList className="h-8">
              <TabsTrigger value="notifications" className="text-xs px-2 h-6">
                <Bell className="w-3 h-3 mr-1" />
                Alerts
              </TabsTrigger>
              <TabsTrigger value="settings" className="text-xs px-2 h-6">
                <Settings className="w-3 h-3 mr-1" />
                Settings
              </TabsTrigger>
            </TabsList>
            {tab === "notifications" && unreadCount > 0 && (
              <Button
                variant="ghost"
                size="sm"
                className="h-6 text-xs"
                onClick={handleMarkAllRead}
                data-testid="button-mark-all-read"
              >
                <Check className="w-3 h-3 mr-1" />
                Mark all
              </Button>
            )}
          </div>

          <TabsContent value="notifications" className="m-0">
            <ScrollArea className="h-80">
              {isLoading ? (
                <div className="p-4 text-center text-sm text-muted-foreground">
                  Loading...
                </div>
              ) : notifications.length === 0 ? (
                <div className="p-8 text-center text-sm text-muted-foreground">
                  <Bell className="w-8 h-8 mx-auto mb-2 opacity-50" />
                  No notifications yet
                </div>
              ) : (
                <div className="divide-y">
                  {notifications.map((notification) => (
                    <NotificationItem
                      key={notification.id}
                      notification={notification}
                      onMarkRead={handleMarkRead}
                    />
                  ))}
                </div>
              )}
            </ScrollArea>
          </TabsContent>

          <TabsContent value="settings" className="m-0">
            <NotificationSettingsPanel
              settings={settings}
              onUpdate={handleUpdateSettings}
            />
          </TabsContent>
        </Tabs>
      </PopoverContent>
    </Popover>
  );
}

server/notificationService.ts.content:
import { storage } from "./storage";
import type { InsertNotification, NotificationType, NotificationSettings } from "@shared/schema";

interface NotificationPayload {
  type: NotificationType;
  title: string;
  message: string;
  exchange?: string;
  symbol?: string;
  pnl?: number;
  data?: Record<string, unknown>;
}

interface WSClient {
  readyState: number;
  send: (data: string) => void;
}

class NotificationService {
  private wsClients: Set<WSClient> = new Set();
  private settings: NotificationSettings | null = null;

  registerClient(ws: WSClient): void {
    this.wsClients.add(ws);
  }

  unregisterClient(ws: WSClient): void {
    this.wsClients.delete(ws);
  }

  private async getSettings(): Promise<NotificationSettings | null> {
    if (!this.settings) {
      this.settings = await storage.getNotificationSettings();
    }
    return this.settings;
  }

  invalidateSettings(): void {
    this.settings = null;
  }

  private shouldNotify(type: NotificationType, settings: NotificationSettings | null, pnl?: number): boolean {
    if (!settings) return true;

    switch (type) {
      case "trade_open":
        return settings.tradeOpenEnabled;
      case "trade_close":
        if (!settings.tradeCloseEnabled) return false;
        if (settings.minPnlAlert && pnl !== undefined) {
          return Math.abs(pnl) >= settings.minPnlAlert;
        }
        return true;
      case "stop_loss":
        return settings.stopLossEnabled;
      case "take_profit":
        return settings.takeProfitEnabled;
      case "trailing_stop":
        // Trailing stop uses stop loss setting since both are exit mechanisms
        return settings.stopLossEnabled;
      case "error":
      case "info":
        return true;
      default:
        return true;
    }
  }

  async notify(payload: NotificationPayload): Promise<void> {
    const settings = await this.getSettings();

    if (!this.shouldNotify(payload.type, settings, payload.pnl)) {
      return;
    }

    try {
      const notification: InsertNotification = {
        type: payload.type,
        title: payload.title,
        message: payload.message,
        exchange: payload.exchange || null,
        symbol: payload.symbol || null,
        pnl: payload.pnl || null,
        data: payload.data ? JSON.stringify(payload.data) : null,
        isRead: false,
      };

      const savedNotification = await storage.createNotification(notification);

      this.broadcastToClients({
        type: "notification",
        notification: savedNotification,
      });

      if (settings?.browserEnabled) {
        this.broadcastToClients({
          type: "browser_notification",
          title: payload.title,
          message: payload.message,
          notificationType: payload.type,
        });
      }

      if (settings?.soundEnabled) {
        this.broadcastToClients({
          type: "play_sound",
          sound: payload.type === "error" ? "error" : payload.pnl && payload.pnl > 0 ? "profit" : "loss",
        });
      }

    } catch (error) {
      console.error("Failed to create notification:", error);
    }
  }

  private broadcastToClients(message: unknown): void {
    const data = JSON.stringify(message);
    this.wsClients.forEach((client) => {
      try {
        if (client.readyState === 1) {
          client.send(data);
        }
      } catch (error) {
        console.error("Failed to send to WebSocket client:", error);
      }
    });
  }

  async notifyTradeOpen(
    exchange: string,
    symbol: string,
    side: string,
    quantity: number,
    price: number,
    executionMode: string
  ): Promise<void> {
    const modeLabel = executionMode === "paper" ? "[PAPER]" : "[REAL]";
    await this.notify({
      type: "trade_open",
      title: `${modeLabel} Position Opened`,
      message: `Opened ${side.toUpperCase()} ${quantity.toFixed(6)} ${symbol} @ $${price.toFixed(2)}`,
      exchange,
      symbol,
      data: { side, quantity, price, executionMode },
    });
  }

  async notifyTradeClose(
    exchange: string,
    symbol: string,
    side: string,
    pnl: number,
    closeReason: string,
    executionMode: string
  ): Promise<void> {
    const modeLabel = executionMode === "paper" ? "[PAPER]" : "[REAL]";
    const pnlLabel = pnl >= 0 ? `+$${pnl.toFixed(2)}` : `-$${Math.abs(pnl).toFixed(2)}`;
    await this.notify({
      type: "trade_close",
      title: `${modeLabel} Position Closed`,
      message: `Closed ${side.toUpperCase()} ${symbol} with PnL: ${pnlLabel} (${closeReason})`,
      exchange,
      symbol,
      pnl,
      data: { side, closeReason, executionMode },
    });
  }

  async notifyStopLoss(
    exchange: string,
    symbol: string,
    side: string,
    pnl: number,
    executionMode: string
  ): Promise<void> {
    const modeLabel = executionMode === "paper" ? "[PAPER]" : "[REAL]";
    await this.notify({
      type: "stop_loss",
      title: `${modeLabel} Stop-Loss Triggered`,
      message: `Stop-loss hit on ${side.toUpperCase()} ${symbol}. Loss: $${Math.abs(pnl).toFixed(2)}`,
      exchange,
      symbol,
      pnl,
      data: { side, executionMode },
    });
  }

  async notifyTakeProfit(
    exchange: string,
    symbol: string,
    side: string,
    pnl: number,
    executionMode: string
  ): Promise<void> {
    const modeLabel = executionMode === "paper" ? "[PAPER]" : "[REAL]";
    await this.notify({
      type: "take_profit",
      title: `${modeLabel} Take-Profit Hit`,
      message: `Take-profit reached on ${side.toUpperCase()} ${symbol}. Profit: +$${pnl.toFixed(2)}`,
      exchange,
      symbol,
      pnl,
      data: { side, executionMode },
    });
  }

  async notifyTrailingStop(
    exchange: string,
    symbol: string,
    side: string,
    pnl: number,
    executionMode: string
  ): Promise<void> {
    const modeLabel = executionMode === "paper" ? "[PAPER]" : "[REAL]";
    const pnlLabel = pnl >= 0 ? `+$${pnl.toFixed(2)}` : `-$${Math.abs(pnl).toFixed(2)}`;
    await this.notify({
      type: "trailing_stop",
      title: `${modeLabel} Trailing Stop Triggered`,
      message: `Trailing stop hit on ${side.toUpperCase()} ${symbol}. PnL: ${pnlLabel}`,
      exchange,
      symbol,
      pnl,
      data: { side, executionMode },
    });
  }

  async notifyError(message: string, details?: Record<string, unknown>): Promise<void> {
    await this.notify({
      type: "error",
      title: "Trading Error",
      message,
      data: details,
    });
  }

  async notifyInfo(title: string, message: string): Promise<void> {
    await this.notify({
      type: "info",
      title,
      message,
    });
  }
}

export const notificationService = new NotificationService();

server/strategyOptimizer.ts.content:
import type { 
  TradingAlgorithm, 
  OptimizationMode, 
  OptimizationSuggestion, 
  LiveStrategyMetrics,
  Ticker,
  Kline,
  Position,
  Exchange,
} from "@shared/schema";
import { analyzeAndRespond } from "./openai";
import { storage } from "./storage";
import { exchangeService } from "./exchangeService";

interface OptimizerConfig {
  exchange: Exchange;
  symbol: string;
  algorithm: TradingAlgorithm;
  optimizationMode: OptimizationMode;
  timeframe: string; // User-selected timeframe for analysis (1m, 5m, 15m, etc.)
  onSuggestion: (suggestion: Omit<OptimizationSuggestion, "id" | "timestamp">) => void;
  onMetricsUpdate: (metrics: LiveStrategyMetrics) => void;
  onAlgorithmUpdate?: (algorithm: TradingAlgorithm) => void;
}

class StrategyOptimizer {
  private config: OptimizerConfig | null = null;
  private metrics: LiveStrategyMetrics | null = null;
  private analysisInterval: NodeJS.Timeout | null = null;
  private isRunning: boolean = false;

  private readonly ANALYSIS_INTERVAL_MS = 60000; // 1 minute between analyses
  private readonly MIN_TRADES_FOR_ANALYSIS = 3;   // Need at least 3 trades before optimizing
  private readonly DRAWDOWN_THRESHOLD = 5;        // Alert if drawdown exceeds 5%
  private readonly WIN_RATE_THRESHOLD = 40;       // Alert if win rate drops below 40%

  async start(config: OptimizerConfig): Promise<void> {
    this.config = config;
    this.isRunning = true;

    // Initialize metrics
    this.metrics = {
      algorithmId: config.algorithm.id,
      sessionStarted: Date.now(),
      tradesExecuted: 0,
      winningTrades: 0,
      losingTrades: 0,
      totalPnl: 0,
      maxDrawdown: 0,
      currentDrawdown: 0,
      peakPnl: 0,
      lastAnalysis: 0,
    };

    console.log(`[StrategyOptimizer] Started in ${config.optimizationMode} mode for ${config.symbol}`);

    // Start periodic analysis
    this.analysisInterval = setInterval(() => {
      this.runAnalysisCycle();
    }, this.ANALYSIS_INTERVAL_MS);

    // Run initial analysis after a short delay
    setTimeout(() => this.runAnalysisCycle(), 10000);
  }

  async stop(): Promise<void> {
    this.isRunning = false;
    if (this.analysisInterval) {
      clearInterval(this.analysisInterval);
      this.analysisInterval = null;
    }
    console.log("[StrategyOptimizer] Stopped");
  }

  // Called by trading bot when a trade is executed
  recordTrade(pnl: number, isWin: boolean): void {
    if (!this.metrics) return;

    this.metrics.tradesExecuted++;
    this.metrics.totalPnl += pnl;

    if (isWin) {
      this.metrics.winningTrades++;
    } else {
      this.metrics.losingTrades++;
    }

    // Update peak and drawdown
    if (this.metrics.totalPnl > this.metrics.peakPnl) {
      this.metrics.peakPnl = this.metrics.totalPnl;
    }

    this.metrics.currentDrawdown = this.metrics.peakPnl - this.metrics.totalPnl;
    if (this.metrics.currentDrawdown > this.metrics.maxDrawdown) {
      this.metrics.maxDrawdown = this.metrics.currentDrawdown;
    }

    // Notify metrics update
    if (this.config) {
      this.config.onMetricsUpdate(this.metrics);
    }

    // Check if we need immediate analysis (significant drawdown or losing streak)
    if (this.shouldTriggerUrgentAnalysis()) {
      this.runAnalysisCycle();
    }
  }

  private shouldTriggerUrgentAnalysis(): boolean {
    if (!this.metrics) return false;

    const winRate = this.metrics.tradesExecuted > 0 
      ? (this.metrics.winningTrades / this.metrics.tradesExecuted) * 100 
      : 50;

    // Trigger if drawdown exceeds threshold
    if (this.metrics.currentDrawdown > this.DRAWDOWN_THRESHOLD) {
      return true;
    }

    // Trigger if win rate drops significantly after enough trades
    if (this.metrics.tradesExecuted >= this.MIN_TRADES_FOR_ANALYSIS && winRate < this.WIN_RATE_THRESHOLD) {
      return true;
    }

    return false;
  }

  private async runAnalysisCycle(): Promise<void> {
    if (!this.config || !this.metrics || !this.isRunning) return;

    // Skip if not enough trades
    if (this.metrics.tradesExecuted < this.MIN_TRADES_FOR_ANALYSIS) {
      console.log(`[StrategyOptimizer] Not enough trades (${this.metrics.tradesExecuted}/${this.MIN_TRADES_FOR_ANALYSIS}) for analysis`);
      return;
    }

    // Prevent too frequent analyses
    const timeSinceLastAnalysis = Date.now() - this.metrics.lastAnalysis;
    if (timeSinceLastAnalysis < this.ANALYSIS_INTERVAL_MS / 2) {
      return;
    }

    this.metrics.lastAnalysis = Date.now();

    try {
      const { exchange, symbol, algorithm, optimizationMode } = this.config;

      // Get current market data - getTicker/getKlines now return result types
      const tickerResult = await exchangeService.getTicker(exchange, symbol);
      const timeframe = this.config.timeframe || "15m";
      const klinesResult = await exchangeService.getKlines(exchange, symbol, timeframe, 50);
      const ticker = tickerResult.ticker;
      const klines = klinesResult.klines;
      const positions = await storage.getPositions(exchange);

      // Calculate performance metrics
      const winRate = this.metrics.tradesExecuted > 0 
        ? (this.metrics.winningTrades / this.metrics.tradesExecuted) * 100 
        : 0;

      // Detect market condition
      const marketCondition = this.detectMarketCondition(klines);
      this.metrics.marketCondition = marketCondition;

      // Build analysis prompt based on optimization mode
      const analysisPrompt = this.buildAnalysisPrompt(
        algorithm,
        this.metrics,
        marketCondition,
        optimizationMode
      );

      console.log(`[StrategyOptimizer] Running analysis... Win Rate: ${winRate.toFixed(1)}%, PnL: $${this.metrics.totalPnl.toFixed(2)}`);

      // Call AI for analysis
      const response = await analyzeAndRespond(analysisPrompt, {
        symbol,
        ticker,
        klines,
        positions,
        tradingMode: algorithm.mode,
        currentAlgorithm: algorithm,
        timeframe,
        riskParameters: algorithm.riskManagement,
        executionMode: "paper",
        marketMaxLeverage: 100,
      });

      // Process AI response
      if (response.algorithm) {
        this.handleOptimizationSuggestion(response.algorithm, response.message, optimizationMode);
      } else if (this.shouldGenerateSuggestion(response.message)) {
        // AI suggested changes but didn't provide full algorithm
        this.handleTextSuggestion(response.message, this.metrics);
      }

    } catch (error) {
      console.error("[StrategyOptimizer] Analysis error:", error);
    }
  }

  private detectMarketCondition(klines: Kline[]): "trending" | "ranging" | "volatile" | "quiet" {
    if (klines.length < 20) return "quiet";

    // Calculate volatility (ATR-like)
    let totalRange = 0;
    for (let i = 1; i < klines.length; i++) {
      totalRange += klines[i].high - klines[i].low;
    }
    const avgRange = totalRange / (klines.length - 1);
    const avgPrice = klines[klines.length - 1].close;
    const volatilityPercent = (avgRange / avgPrice) * 100;

    // Calculate trend strength
    const firstPrice = klines[0].close;
    const lastPrice = klines[klines.length - 1].close;
    const priceChange = ((lastPrice - firstPrice) / firstPrice) * 100;

    // Classify market condition
    if (volatilityPercent > 2) {
      return Math.abs(priceChange) > 3 ? "trending" : "volatile";
    } else if (Math.abs(priceChange) > 2) {
      return "trending";
    } else if (volatilityPercent < 0.5) {
      return "quiet";
    } else {
      return "ranging";
    }
  }

  private buildAnalysisPrompt(
    algorithm: TradingAlgorithm,
    metrics: LiveStrategyMetrics,
    marketCondition: string,
    optimizationMode: OptimizationMode
  ): string {
    const winRate = metrics.tradesExecuted > 0 
      ? (metrics.winningTrades / metrics.tradesExecuted) * 100 
      : 0;

    let modeInstruction = "";
    switch (optimizationMode) {
      case "manual":
        modeInstruction = "Suggest specific improvements but DO NOT generate a new algorithm unless explicitly asked. Focus on explaining what parameters should change and why.";
        break;
      case "semi-auto":
        modeInstruction = "You may generate an updated algorithm with adjusted parameters (entry thresholds, stop-loss levels, position sizing). Keep the core strategy logic intact.";
        break;
      case "full-auto":
        modeInstruction = "You may generate a completely new algorithm if the current strategy is not performing well in current market conditions.";
        break;
    }

    return `STRATEGY OPTIMIZATION ANALYSIS

Current Algorithm: "${algorithm.name}"
Mode: ${algorithm.mode}

LIVE PERFORMANCE METRICS:
- Trades Executed: ${metrics.tradesExecuted}
- Win Rate: ${winRate.toFixed(1)}%
- Total PnL: $${metrics.totalPnl.toFixed(2)}
- Current Drawdown: $${metrics.currentDrawdown.toFixed(2)}
- Max Drawdown: $${metrics.maxDrawdown.toFixed(2)}
- Session Duration: ${Math.round((Date.now() - metrics.sessionStarted) / 60000)} minutes

MARKET CONDITION: ${marketCondition.toUpperCase()}

CURRENT STRATEGY RULES:
${JSON.stringify(algorithm.rules, null, 2)}

RISK MANAGEMENT:
${JSON.stringify(algorithm.riskManagement, null, 2)}

OPTIMIZATION MODE: ${optimizationMode.toUpperCase()}
${modeInstruction}

Analyze the strategy performance against current market conditions. Consider:
1. Is the strategy suited for the current ${marketCondition} market?
2. Are the entry/exit conditions optimal?
3. Is the risk management appropriate given the performance?
4. What specific changes would improve performance?

${optimizationMode !== "manual" ? "If you recommend changes, provide an updated algorithm JSON." : "Provide specific recommendations for the user to review."}`;
  }

  private shouldGenerateSuggestion(message: string): boolean {
    const suggestionKeywords = [
      "suggest", "recommend", "adjust", "increase", "decrease",
      "tighten", "loosen", "modify", "change", "improve", "optimize"
    ];
    const lowerMessage = message.toLowerCase();
    return suggestionKeywords.some(keyword => lowerMessage.includes(keyword));
  }

  private handleOptimizationSuggestion(
    suggestedAlgorithm: TradingAlgorithm,
    reason: string,
    optimizationMode: OptimizationMode
  ): void {
    if (!this.config || !this.metrics) return;

    const winRate = this.metrics.tradesExecuted > 0 
      ? (this.metrics.winningTrades / this.metrics.tradesExecuted) * 100 
      : 0;

    // Determine suggestion type and whether to auto-apply
    // "manual" mode: all suggestions require user approval
    // "semi-auto" mode: parameter adjustments are auto-applied
    // "full-auto" mode: all changes are auto-applied
    const shouldAutoApply = optimizationMode === "full-auto" || optimizationMode === "semi-auto";

    const suggestion: Omit<OptimizationSuggestion, "id" | "timestamp"> = {
      type: optimizationMode === "semi-auto" ? "parameter" : "full",
      reason: reason.slice(0, 500), // Truncate for display
      suggestedAlgorithm,
      performanceContext: {
        winRate,
        totalPnl: this.metrics.totalPnl,
        recentTrades: this.metrics.tradesExecuted,
        drawdown: this.metrics.currentDrawdown,
      },
      status: shouldAutoApply ? "auto-applied" : "pending",
    };

    // Auto-apply for semi-auto and full-auto modes
    if (shouldAutoApply && this.config.onAlgorithmUpdate) {
      console.log(`[StrategyOptimizer] Auto-applying optimization in ${optimizationMode} mode`);
      this.config.onAlgorithmUpdate(suggestedAlgorithm);
    }

    // Notify about the suggestion
    this.config.onSuggestion(suggestion);
  }

  private handleTextSuggestion(message: string, metrics: LiveStrategyMetrics): void {
    if (!this.config) return;

    const winRate = metrics.tradesExecuted > 0 
      ? (metrics.winningTrades / metrics.tradesExecuted) * 100 
      : 0;

    const suggestion: Omit<OptimizationSuggestion, "id" | "timestamp"> = {
      type: "parameter",
      reason: message.slice(0, 500),
      performanceContext: {
        winRate,
        totalPnl: metrics.totalPnl,
        recentTrades: metrics.tradesExecuted,
        drawdown: metrics.currentDrawdown,
      },
      status: "pending",
    };

    this.config.onSuggestion(suggestion);
  }

  getMetrics(): LiveStrategyMetrics | null {
    return this.metrics;
  }

  isActive(): boolean {
    return this.isRunning;
  }
}

export const strategyOptimizer = new StrategyOptimizer();

