import crypto from "crypto";
import type { Market, Ticker, Kline, ApiCredentials } from "@shared/schema";

const BITUNIX_FUTURES_URL = "https://fapi.bitunix.com";
const BITUNIX_SPOT_URL = "https://api.bitunix.com";

export interface ApiResult<T> {
  success: boolean;
  data: T | null;
  error?: string;
  errorCode?: string;
}

interface BitunixTradingPair {
  symbol: string;
  base: string;
  quote: string;
  minTradeVolume: string;
  maxLeverage: number;
  basePrecision: number;
  quotePrecision: number;
  symbolStatus: string;
}

interface BitunixTicker {
  symbol: string;
  lastPrice: string;
  markPrice: string;
  high24h: string;
  low24h: string;
  volume24h: string;
  priceChange24h: string;
  priceChangePercent24h: string;
  ts: number;
}

function sha256Hex(input: string): string {
  return crypto.createHash("sha256").update(input, "utf8").digest("hex");
}

function getTimestampYYYYMMDDHHMMSS(): string {
  const now = new Date();
  const year = now.getUTCFullYear();
  const month = String(now.getUTCMonth() + 1).padStart(2, "0");
  const day = String(now.getUTCDate()).padStart(2, "0");
  const hours = String(now.getUTCHours()).padStart(2, "0");
  const minutes = String(now.getUTCMinutes()).padStart(2, "0");
  const seconds = String(now.getUTCSeconds()).padStart(2, "0");
  return `${year}${month}${day}${hours}${minutes}${seconds}`;
}

function generateBitunixSignature(
  apiKey: string,
  secretKey: string,
  timestamp: string,
  nonce: string,
  queryParams: string,
  body: string
): string {
  // Bitunix uses double SHA256, not HMAC
  // Step 1: digest = SHA256(nonce + timestamp + apiKey + queryParams + body)
  const digestInput = nonce + timestamp + apiKey + queryParams + body;
  const digest = sha256Hex(digestInput);

  // Step 2: sign = SHA256(digest + secretKey)
  const signInput = digest + secretKey;
  const signature = sha256Hex(signInput);

  return signature;
}

function createBitunixHeaders(
  credentials: ApiCredentials,
  queryParams: string = "",
  body: string = ""
): Record<string, string> {
  const timestamp = getTimestampYYYYMMDDHHMMSS();
  const nonce = crypto.randomBytes(16).toString("hex");
  const signature = generateBitunixSignature(
    credentials.apiKey,
    credentials.secretKey,
    timestamp,
    nonce,
    queryParams,
    body
  );

  return {
    "api-key": credentials.apiKey,
    "sign": signature,
    "timestamp": timestamp,
    "nonce": nonce,
    "Content-Type": "application/json",
  };
}

async function fetchWithTimeout(
  url: string,
  options: RequestInit = {},
  timeoutMs: number = 10000
): Promise<Response> {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const response = await fetch(url, {
      ...options,
      signal: controller.signal,
    });
    return response;
  } finally {
    clearTimeout(timeout);
  }
}

export async function getBitunixMarkets(): Promise<Market[]> {
  try {
    const response = await fetchWithTimeout(
      `${BITUNIX_FUTURES_URL}/api/v1/futures/market/trading_pairs`
    );

    if (!response.ok) {
      console.error(`Bitunix markets API error: ${response.status}`);
      return [];
    }

    const result = await response.json();

    if (result.code !== 0 || !result.data) {
      console.error("Bitunix markets response error:", result.msg || "No data");
      return [];
    }

    return result.data
      .filter((pair: BitunixTradingPair) => 
        pair.symbolStatus === "OPEN" && pair.quote === "USDT"
      )
      .map((pair: BitunixTradingPair) => ({
        symbol: pair.symbol,
        baseAsset: pair.base,
        quoteAsset: pair.quote,
        pricePrecision: pair.quotePrecision || 2,
        quantityPrecision: pair.basePrecision || 4,
        maxLeverage: pair.maxLeverage || 125,
      }));
  } catch (error) {
    console.error("Failed to fetch Bitunix markets:", error);
    return [];
  }
}

export async function getBitunixTicker(symbol: string): Promise<ApiResult<Ticker>> {
  try {
    const response = await fetchWithTimeout(
      `${BITUNIX_FUTURES_URL}/api/v1/futures/market/tickers?symbols=${symbol}`
    );

    if (!response.ok) {
      return {
        success: false,
        data: null,
        error: `HTTP ${response.status}`,
        errorCode: `HTTP_${response.status}`,
      };
    }

    const result = await response.json();

    if (result.code !== 0 || !result.data || result.data.length === 0) {
      return {
        success: false,
        data: null,
        error: result.msg || "No ticker data",
        errorCode: "NO_DATA",
      };
    }

    const ticker = result.data[0];
    const lastPrice = parseFloat(ticker.lastPrice || ticker.last || "0");
    const openPrice = parseFloat(ticker.open || "0");
    const priceChange = lastPrice - openPrice;
    const priceChangePercent = openPrice > 0 ? ((priceChange / openPrice) * 100) : 0;

    return {
      success: true,
      data: {
        symbol,
        lastPrice,
        priceChange,
        priceChangePercent,
        high24h: parseFloat(ticker.high || "0"),
        low24h: parseFloat(ticker.low || "0"),
        volume24h: parseFloat(ticker.quoteVol || ticker.baseVol || "0"),
        timestamp: Date.now(),
      },
    };
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : "Unknown error";
    return {
      success: false,
      data: null,
      error: errorMsg,
      errorCode: "FETCH_ERROR",
    };
  }
}

export async function getBitunixKlines(
  symbol: string,
  timeframe: string,
  limit: number = 100
): Promise<ApiResult<Kline[]>> {
  try {
    const interval = mapTimeframeToInterval(timeframe);
    const response = await fetchWithTimeout(
      `${BITUNIX_FUTURES_URL}/api/v1/futures/market/kline?symbol=${symbol}&interval=${interval}&limit=${limit}`
    );

    if (!response.ok) {
      return {
        success: false,
        data: null,
        error: `HTTP ${response.status}`,
        errorCode: `HTTP_${response.status}`,
      };
    }

    const result = await response.json();

    if (result.code !== 0 || !result.data || result.data.length === 0) {
      return {
        success: false,
        data: null,
        error: result.msg || "No klines data",
        errorCode: "NO_DATA",
      };
    }

    const klines: Kline[] = result.data.map((k: any) => ({
      time: k.time || k.ts || k.t,
      open: parseFloat(k.open || "0"),
      high: parseFloat(k.high || "0"),
      low: parseFloat(k.low || "0"),
      close: parseFloat(k.close || "0"),
      volume: parseFloat(k.quoteVol || k.baseVol || "0"),
    })).sort((a, b) => a.time - b.time);

    return {
      success: true,
      data: klines,
    };
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : "Unknown error";
    return {
      success: false,
      data: null,
      error: errorMsg,
      errorCode: "FETCH_ERROR",
    };
  }
}

function mapTimeframeToInterval(timeframe: string): string {
  const mapping: Record<string, string> = {
    "1m": "1m",
    "5m": "5m",
    "15m": "15m",
    "30m": "30m",
    "1h": "1h",
    "2h": "2h",
    "4h": "4h",
    "6h": "6h",
    "8h": "8h",
    "12h": "12h",
    "1d": "1d",
    "1D": "1d",
    "3d": "3d",
    "1w": "1w",
    "1M": "1M",
  };
  return mapping[timeframe] || "15m";
}

export async function validateBitunixCredentials(
  credentials: ApiCredentials
): Promise<boolean> {
  try {
    // For the account endpoint, we need to pass marginCoin parameter
    // Query params must be in format: key1value1key2value2 (no = or &)
    const marginCoin = "USDT";
    const queryParamsForSignature = `marginCoin${marginCoin}`;
    const queryStringForUrl = `marginCoin=${marginCoin}`;

    const headers = createBitunixHeaders(credentials, queryParamsForSignature);
    const url = `${BITUNIX_FUTURES_URL}/api/v1/futures/account?${queryStringForUrl}`;

    console.log("[BITUNIX] Validating credentials with endpoint:", url);
    console.log("[BITUNIX] Query params for signature:", queryParamsForSignature);
    console.log("[BITUNIX] Headers:", JSON.stringify(headers));

    const response = await fetchWithTimeout(url, {
      method: "GET",
      headers,
    });

    const data = await response.json();
    console.log("[BITUNIX] Validation response:", JSON.stringify(data));

    if (response.ok && data.code === 0) {
      console.log("[BITUNIX] Credentials validated successfully");
      return true;
    }

    console.warn("[BITUNIX] Validation failed - code:", data.code, "msg:", data.msg);
    return false;
  } catch (error) {
    console.warn("[BITUNIX] Credential validation error:", error);
    return false;
  }
}

// Balance info types
export interface ExchangeBalance {
  asset: string;
  available: number;
  frozen: number;
  total: number;
  unrealizedPnl: number;
  marginBalance: number;
}

// Order types for Bitunix
export interface PlaceOrderParams {
  symbol: string;
  side: "BUY" | "SELL";
  orderType: "LIMIT" | "MARKET";
  qty: string;
  price?: string;
  tradeSide?: "OPEN" | "CLOSE";
  positionId?: string;
  reduceOnly?: boolean;
  effect?: "GTC" | "IOC" | "FOK";
  clientId?: string;
  leverage?: number;
}

export interface BitunixOrderResponse {
  orderId: string;
  clientId?: string;
  symbol: string;
  side: string;
  price: string;
  qty: string;
  orderType: string;
  status: string;
  filledQty?: string;
  avgPrice?: string;
  createTime?: number;
}

export interface BitunixPosition {
  positionId: string;
  symbol: string;
  side: string;
  qty: string;
  entryPrice: string;
  markPrice: string;
  unrealizedPnl: string;
  leverage: string;
  marginMode: string;
  liquidationPrice: string;
  margin: string;
}

// Place a single order on Bitunix
export async function placeBitunixOrder(
  credentials: ApiCredentials,
  params: PlaceOrderParams
): Promise<ApiResult<BitunixOrderResponse>> {
  try {
    const body: Record<string, any> = {
      symbol: params.symbol,
      side: params.side,
      qty: params.qty,
      orderType: params.orderType,
      tradeSide: params.tradeSide || "OPEN",
      effect: params.effect || "GTC",
    };

    // Add price for limit orders
    if (params.orderType === "LIMIT" && params.price) {
      body.price = params.price;
    }

    // For closing positions
    if (params.positionId) {
      body.positionId = params.positionId;
    }

    if (params.reduceOnly !== undefined) {
      body.reduceOnly = params.reduceOnly;
    }

    if (params.clientId) {
      body.clientId = params.clientId;
    }

    const bodyStr = JSON.stringify(body);
    const headers = createBitunixHeaders(credentials, "", bodyStr);
    const url = `${BITUNIX_FUTURES_URL}/api/v1/futures/trade/place_order`;

    console.log("[BITUNIX] Placing order:", url);
    console.log("[BITUNIX] Order body:", bodyStr);

    const response = await fetchWithTimeout(url, {
      method: "POST",
      headers,
      body: bodyStr,
    });

    const data = await response.json();
    console.log("[BITUNIX] Order response:", JSON.stringify(data));

    if (!response.ok || data.code !== 0) {
      return {
        success: false,
        data: null,
        error: data.msg || `Order failed with code ${data.code}`,
        errorCode: `BITUNIX_${data.code}`,
      };
    }

    return {
      success: true,
      data: data.data as BitunixOrderResponse,
    };
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    console.error("[BITUNIX] Failed to place order:", errorMessage);
    return {
      success: false,
      data: null,
      error: `Failed to place order: ${errorMessage}`,
      errorCode: "NETWORK_ERROR",
    };
  }
}

// Set leverage for a symbol
export async function setBitunixLeverage(
  credentials: ApiCredentials,
  symbol: string,
  leverage: number,
  marginMode: "ISOLATION" | "CROSS" = "ISOLATION"
): Promise<ApiResult<boolean>> {
  try {
    const body = {
      symbol,
      leverage: leverage.toString(),
      marginMode,
    };
    const bodyStr = JSON.stringify(body);
    const headers = createBitunixHeaders(credentials, "", bodyStr);
    const url = `${BITUNIX_FUTURES_URL}/api/v1/futures/account/set_leverage`;

    console.log("[BITUNIX] Setting leverage:", symbol, leverage, marginMode);

    const response = await fetchWithTimeout(url, {
      method: "POST",
      headers,
      body: bodyStr,
    });

    const data = await response.json();
    console.log("[BITUNIX] Set leverage response:", JSON.stringify(data));

    if (!response.ok || data.code !== 0) {
      // Code 40023 typically means leverage is already set - treat as success
      if (data.code === 40023) {
        return { success: true, data: true };
      }
      return {
        success: false,
        data: false,
        error: data.msg || `Failed to set leverage`,
        errorCode: `BITUNIX_${data.code}`,
      };
    }

    return { success: true, data: true };
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    console.error("[BITUNIX] Failed to set leverage:", errorMessage);
    return {
      success: false,
      data: false,
      error: `Failed to set leverage: ${errorMessage}`,
      errorCode: "NETWORK_ERROR",
    };
  }
}

// Get current positions from Bitunix
export async function getBitunixPositions(
  credentials: ApiCredentials
): Promise<ApiResult<BitunixPosition[]>> {
  try {
    const headers = createBitunixHeaders(credentials);
    const url = `${BITUNIX_FUTURES_URL}/api/v1/futures/position/get_pending_positions`;

    console.log("[BITUNIX] Fetching positions");

    const response = await fetchWithTimeout(url, {
      method: "GET",
      headers,
    });

    const data = await response.json();
    console.log("[BITUNIX] Positions response:", JSON.stringify(data));

    if (!response.ok || data.code !== 0) {
      return {
        success: false,
        data: null,
        error: data.msg || "Failed to fetch positions",
        errorCode: `BITUNIX_${data.code}`,
      };
    }

    return {
      success: true,
      data: (data.data || []) as BitunixPosition[],
    };
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    console.error("[BITUNIX] Failed to fetch positions:", errorMessage);
    return {
      success: false,
      data: null,
      error: `Failed to fetch positions: ${errorMessage}`,
      errorCode: "NETWORK_ERROR",
    };
  }
}

// Cancel an order on Bitunix
export async function cancelBitunixOrder(
  credentials: ApiCredentials,
  symbol: string,
  orderId: string
): Promise<ApiResult<boolean>> {
  try {
    const body = { symbol, orderId };
    const bodyStr = JSON.stringify(body);
    const headers = createBitunixHeaders(credentials, "", bodyStr);
    const url = `${BITUNIX_FUTURES_URL}/api/v1/futures/trade/cancel_order`;

    console.log("[BITUNIX] Canceling order:", orderId);

    const response = await fetchWithTimeout(url, {
      method: "POST",
      headers,
      body: bodyStr,
    });

    const data = await response.json();
    console.log("[BITUNIX] Cancel order response:", JSON.stringify(data));

    if (!response.ok || data.code !== 0) {
      return {
        success: false,
        data: false,
        error: data.msg || "Failed to cancel order",
        errorCode: `BITUNIX_${data.code}`,
      };
    }

    return { success: true, data: true };
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    console.error("[BITUNIX] Failed to cancel order:", errorMessage);
    return {
      success: false,
      data: false,
      error: `Failed to cancel order: ${errorMessage}`,
      errorCode: "NETWORK_ERROR",
    };
  }
}

// Close a position on Bitunix (market order)
export async function closeBitunixPosition(
  credentials: ApiCredentials,
  positionId: string,
  symbol: string,
  side: string,
  qty: string
): Promise<ApiResult<BitunixOrderResponse>> {
  // To close a position, we need to place an opposite order
  // If position is LONG (BUY side), we SELL to close
  // If position is SHORT (SELL side), we BUY to close
  const closeSide = side.toUpperCase() === "LONG" || side.toUpperCase() === "BUY" ? "SELL" : "BUY";

  return placeBitunixOrder(credentials, {
    symbol,
    side: closeSide as "BUY" | "SELL",
    orderType: "MARKET",
    qty,
    tradeSide: "CLOSE",
    positionId,
    reduceOnly: true,
  });
}

export async function getBitunixBalance(credentials: ApiCredentials): Promise<ApiResult<ExchangeBalance[]>> {
  try {
    const marginCoin = "USDT";
    const queryParamsForSignature = `marginCoin${marginCoin}`;
    const queryStringForUrl = `marginCoin=${marginCoin}`;

    const headers = createBitunixHeaders(credentials, queryParamsForSignature);
    const url = `${BITUNIX_FUTURES_URL}/api/v1/futures/account?${queryStringForUrl}`;

    const response = await fetchWithTimeout(url, {
      method: "GET",
      headers,
    });

    if (!response.ok) {
      return {
        success: false,
        data: null,
        error: `Bitunix balance API returned status ${response.status}`,
        errorCode: "HTTP_ERROR"
      };
    }

    const data = await response.json();

    if (data.code !== 0) {
      return {
        success: false,
        data: null,
        error: data.msg || "Failed to fetch balance",
        errorCode: "API_ERROR"
      };
    }

    const balances: ExchangeBalance[] = [];
    const accountData = data.data;

    if (accountData) {
      // Bitunix returns account info with available, frozen, unrealizedPnl, etc.
      const available = parseFloat(accountData.available || accountData.availableBalance || "0");
      const frozen = parseFloat(accountData.frozen || accountData.frozenBalance || "0");
      const unrealizedPnl = parseFloat(accountData.unrealizedPnl || accountData.unrealizedProfit || "0");
      const marginBalance = parseFloat(accountData.marginBalance || accountData.equity || "0");

      balances.push({
        asset: accountData.marginCoin || "USDT",
        available,
        frozen,
        total: available + frozen,
        unrealizedPnl,
        marginBalance: marginBalance || (available + frozen + unrealizedPnl),
      });
    }

    return {
      success: true,
      data: balances
    };
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    console.error("[BITUNIX] Failed to fetch balance:", errorMessage);
    return {
      success: false,
      data: null,
      error: `Failed to fetch Bitunix balance: ${errorMessage}`,
      errorCode: "NETWORK_ERROR"
    };
  }
}

